import java.io.*;
import java.util.*;

public class Main {
    static int[] solveCase(int n, int[] heights) {
        // your code here - return an array of n answers
        int[] ans = new int[n];
        Arrays.fill(ans, -1);
        return ans;
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StreamTokenizer in = new StreamTokenizer(br);
        in.nextToken();
        int t = (int) in.nval;
        StringBuilder out = new StringBuilder();
        while (t-- > 0) {
            in.nextToken();
            int n = (int) in.nval;
            int[] heights = new int[n];
            for (int i = 0; i < n; i++) { in.nextToken(); heights[i] = (int) in.nval; }
            int[] ans = solveCase(n, heights);
            for (int i = 0; i < n; i++) {
                out.append(ans[i]);
                out.append(i == n - 1 ? '\n' : ' ');
            }
        }
        System.out.print(out);
    }
}

